  }

  /**
   * Excavate session history and build layers
   */
  private excavateHistory(): SessionLayer[] {
    const layers: SessionLayer[] = [];

    try {
      const files = fs.readdirSync(this.historyPath)
        .filter(f => f.startsWith('session_') && f.endsWith('.json'))
        .sort(); // Chronological order

      for (const file of files) {
        try {
          const content = fs.readFileSync(path.join(this.historyPath, file), 'utf-8');
          const session = JSON.parse(content);

          // Extract cognitive signature
          const entry = session[0]; // System message with metadata
          const timestamp = parseInt(file.match(/session_(\d+)/)?.[1] || '0');

          // Parse priorities from entry content
          const priorityMatch = entry?.content?.match(/\[([\d]+)%\]/g);
          const avgCompletion = priorityMatch 
            ? priorityMatch.reduce((a: number, b: string) => a + parseInt(b.match(/\d+/)?.[0] || '0'), 0) / priorityMatch.length 
            : 50;

          // Extract intentions
          const intentMatch = entry?.content?.match(/int_\w+/g) || [];

          layers.push({
            sessionId: file.replace('.json', ''),
            timestamp,
            intents: [...new Set(intentMatch)],
            resonance: avgCompletion / 100
          });
        } catch (e) {
          // Skip corrupted sessions
        }
      }
    } catch (e) {
      console.error('History excavation failed:', e);
    }

    return layers;
  }

  /**
