        const intentStr = layer.intents.slice(0, 2).join(', ');
        output += `${indent}  в””в”Җв–ё ${intentStr}\n`;
      }
    }

    output += '\n';
    return output;
  }

  /**
   * Create map of intention persistence across layers
   */
  private generateIntentMap(): string {
    let output = 'в•ӯв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җ INTENTION SEDIMENTATION в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв•®\n';
    output += 'в”Ӯ How intentions persist and evolve across time в”Ӯ\n';
    output += 'в•°в”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв”Җв•Ҝ\n\n';

