      output += line + '\n';
    }

    return output;
  }

  save(): string {
    const content = this.generate();
    const filename = 'dream_entropy_' + this.sessionId + '.txt';
    const outPath = path.join(process.cwd(), 'artifacts', filename);
    fs.writeFileSync(outPath, content);
    return outPath;
  }
}

export default DreamEntropy;
